export function getNpExamCategoryBySlug(slug: string): NpCategoryPage | undefined {
  return npExamCategories.find(c => c.slug === slug);
}

export function getNpExamConditionBySlug(slug: string): NpConditionPage | undefined {
  return npExamConditions.find(c => c.slug === slug);
}

export function getNpExamMedicationBySlug(slug: string): NpMedicationPage | undefined {
  return npExamMedications.find(m => m.slug === slug);
}

export function getNpExamLabValueBySlug(slug: string): NpLabValuePage | undefined {
  return npExamLabValues.find(l => l.slug === slug);
}

export function getNpExamComparisonBySlug(slug: string): NpComparisonPage | undefined {
  return npExamComparisons.find(c => c.slug === slug);
}

export function getNpExamStrategyBySlug(slug: string): NpStrategyPage | undefined {
  return npExamStrategies.find(s => s.slug === slug);
}

export function getNpExamCaseStudyBySlug(slug: string): NpCaseStudyPage | undefined {
  return npExamCaseStudies.find(cs => cs.slug === slug);
}

